const conversationPlans={
  sam:[['South Carolina','A reigning champion voluntarily chose Columbia. Somebody frame the evidence bag and hang it above the tunnel.'],['Florida State','Respect the move, but the title defense has to survive Tallahassee eventually. Glenn is already measuring the visitor sideline.'],['California','Dusty wants to know whether the evidence bag can safely transport a headset and six unlicensed cosmic stones.']],
  jordan:[['Universidad México','My grandfather waited his entire life to see a Mexican school enter this stage. Now give us an opening kickoff time.'],['Arizona','An international expansion team with UCLA transfers is exactly the kind of chaos this dynasty needed.'],['South Carolina','Sam is going to need a passport, a warrant, and extra oxygen for that road game.'],['California','Berkeley supports international education and absolutely wants access to that altitude research.']],
  chris:[['Arizona','The veterans keep calling him the kid. Arizona is giving Chris the chance to make them call him Coach.'],['California','Dusty taught him plenty. Now Chris has to prove which parts became his own.']],
  glenn:[['Florida State','Duke fumbled the contract and Florida State recovered it. Welcome to Tallahassee, Coach Blueprint.'],['South Carolina','Sam has classified the broken Duke negotiations as a cold case.'],['Arizona','Does the Table Saw package come with a play clock warning or do we just find out live?']],
  dusty:[['California','The old coaching search was worth it. Berkeley finally found the only man who ranks jobs by scoreboard wiring access.'],['Universidad México','Jordan knew Dusty would land somewhere with enough engineering students to understand him.']],
  'dusty-cal':[['California','We got the coach, the five-star follower, and whatever Warranty Bear means. Great day to be a Golden Bear.'],['Arizona','Chris changing the family Wi-Fi password before congratulating his dad is elite rivalry preparation.'],['South Carolina','Sam requests a complete inventory of every unlabeled toolbox crossing into Berkeley.'],['Florida State','Glenn will build the reinforced bench. Cal should probably reinforce the electrical room too.']],
  oleary:[['Universidad México','Nick O’Leary joining the staff is serious football business. The Dusty assignment is simply an essential duty.'],['California','If that man appears in Berkeley asking what happened last time, Dusty is calling campus security.'],['South Carolina','Sam refuses to investigate until somebody finally explains what happened last time.']],
  'sam-arizona-arrests':[['Arizona','Running a suspicious route is not a crime, Sam. Free the tempo four.'],['South Carolina','That Gatorade bottle failed to provide a credible alibi. The questioning was justified.'],['California','Dusty can enhance the parking-lot footage, but payment must be made in replacement controller parts.'],['Florida State','Glenn reviewed the evidence and says the cone placement was structurally unsound.'],['Universidad México','UMX legal has advised every receiver to remain silent until the international film crew arrives.']],
  'chris-ps4-playbook':[['Arizona','Family console, family playbook. That is settled law in Tucson.'],['California','Absolutely not. Dusty paid for that PS4 and the controller still drifts left because of Chris.'],['South Carolina','Sam needs the console secured before the save file becomes inadmissible.'],['Universidad México','Jordan remembers the original Ask Jordan formation and says Chris copied the wrong version.']],
  headset:[['South Carolina','Return the championship headset and no questions will be asked for the first five minutes.'],['Florida State','Glenn can build a replacement, but everyone knows a replica does not carry the curse.'],['Arizona','Check the PS4 room. This family keeps every dangerous football artifact in one place.']],
  'umx-uniforms':[['Universidad México','Noche Azteca under the Mexico City lights is going to look unfair before the ball is even snapped.'],['California','Dusty saw those uniforms once and immediately ordered a welding glove. This is UMX’s fault.'],['Arizona','The white set is clean. Chris knows the youngest coach still has to look ready for the biggest stage.'],['Florida State','That gold detailing passed inspection. Glenn approves the craftsmanship.']],
  'umx-time-chamber':[['Universidad México','Our freshman quarterback has a 401(k), perfect footwork, and four years of eligibility. Please respect his privacy.'],['South Carolina','Sam is requesting birth certificates from before and after every chamber session.'],['Arizona','A 30-year-old freshman still has to defend 104 snaps in the desert. Good luck, uncle.'],['California','Dusty only needs five minutes inside to finish designing the next 40 years of formations.'],['Florida State','Glenn wants confirmation that chamber years count toward recruiting relationship length.']],
  'sam-ncaa-compliance':[['South Carolina','College football needed accountability. Sam brought a binder, body-camera recommendations, and office hours.'],['Arizona','“Football probable cause” sounds suspiciously like Sam wants to arrest our slot receiver again.'],['Universidad México','Before rewriting the NCAA manual, please add a section recognizing time-dilated international freshmen.']],
  'dusty-infinity-uniforms':[['California','Blue jersey, gold pants, six stones. That is a completely normal equipment progression.'],['Universidad México','UMX accepts responsibility for inspiring the design but rejects liability for erased depth charts.'],['South Carolina','Sam has already opened separate investigations into each stone.'],['Arizona','Chris says a cosmic glove will not help Dusty when his son finally gets the chance to prove himself against him.']],
  'glenn-recruiting-foundation':[['Florida State','No carousel talk. No shortcuts. Stack recruiting classes and make Tallahassee terrifying again.'],['South Carolina','Stability is a strong pitch, but Sam will be checking every prospect’s paperwork.'],['Arizona','Glenn has experience and a blueprint. Chris has a career to prove he belongs beside builders like him.']],
  'dusty-washington':[['Washington','Purple toolbox secured. Give Dusty the stadium schematics and let the MacGyver Multiple loose.'],['California','That was the shortest warranty period in Berkeley history. We are keeping the infinity-gauntlet sketches.'],['BYU','Another veteran moves, another future chance for Chris to prove himself against his father.'],['Universidad México','Jordan already sent Nick O’Leary the Seattle address. International torment has no borders.'],['South Carolina','Sam requests chain-of-custody paperwork for the five-star quarterback and every extension cord.']],
  'chris-byu':[['BYU','Provo is not borrowing Dusty’s son. It is hiring Chris Cathcart to build a name that stands on its own.'],['Arizona','We gave him his first shot and lost him before kickoff. Keep the PS4 evidence in the archive.'],['Washington','Dusty says he is proud. He also changed every password in Seattle.'],['Universidad México','Jordan already circled the BYU matchup. Uncle privileges do not survive kickoff.'],['Florida State','Glenn remembers a Utah night shift that prepared him for this exact move. No follow-up questions.']]
  ,'schedule-release':[['Universidad México','The first game in program history is against the reigning champion in Mexico City. Perfect. No quiet entrances.'],['Washington','Dusty starts at BYU against Chris, then gets Florida State in Seattle. Somebody reinforce the family group chat.'],['South Carolina','Passport packed. Evidence bag sealed. Sam is taking the title to Mexico City in Week 1.'],['BYU','The youngest coach gets his father in his very first game at BYU. This is the chance Chris came here to earn.'],['Florida State','SMU on Monday night, Miami on the road, Florida at home. Glenn may need to decline a few side jobs.']]
  ,'sneaky-speed':[['South Carolina','Nyck Harbor at 99 speed is not sneaky once the safety realizes the cushion is already gone.'],['Universidad México','Rodrick Pleasant has 99 speed and 99 acceleration at altitude. Visiting receivers should pack oxygen and shorter routes.'],['BYU','E. Johnson and T. Alexander III give Chris the recovery speed to be aggressive. Now prove it against Washington.'],['Florida State','M. Danzy has 95 speed, 97 acceleration, and a coach who has probably worked a track-meet shift before.']]
  ,'week-0-finals':[['Florida State','Louisville scored 48, Virginia survived, and NC State lost by three. Glenn just picked up three extra film-review shifts.'],['South Carolina','Week 0 evidence logged. Sam would like every Week 1 opponent to preserve its game film and remain available for questioning.'],['Universidad México','Nine finals are complete. Now the world waits for the first NCAA kickoff in Mexico City.']]
  ,'sc-umx-week1':[['South Carolina','Down 21–7, then 63 points the rest of the way. The champion did not panic; he opened a larger evidence bag.'],['Universidad México','The first quarter proved the Panteras belong. The next three proved the first lesson is going to hurt for a while.'],['BYU','Chris watched a 21–7 lead disappear and wrote one note before Washington: finish every quarter.'],['Washington','Dusty has classified the second-half South Carolina film as a controlled avalanche.'],['Florida State','Glenn says surrendering 63 points after the first quarter creates several available film-room shifts. He took all of them.']]
  ,'college-football-tonight-sc-umx':[['South Carolina','The College Football Tonight tape starts at 21–7 and ends with the champion submitting 63 unanswered reasons to keep watching.'],['Universidad México','Keep the first-quarter film and burn the fourth-quarter film. Historic debut, brutal lesson, next game.'],['Washington','Dusty paused the recap at the momentum swing and labeled it: what happens when the emergency repair works too well.'],['BYU','Chris saw exactly why the youngest coach cannot relax after an early lead. Finish the game or become the recap.']]
  ,'fsu-smu-week1':[['Florida State','Wisner gave Glenn four touchdowns and a ranked win on his first shift. That résumé keeps getting stranger and better.'],['South Carolina','Sam has logged 592 yards and a plus-two turnover margin as evidence that Florida State is officially dangerous.'],['Universidad México','A 68-yard run and four rushing touchdowns? Mexico City requests a future time-chamber appointment for Wisner.'],['Washington','Dusty respects any repair job that begins down 10–3 and ends with the No. 22 team leaving 31–20.']]
  ,'ncaa-midseason-clock-rule':[['South Carolina','Sam wants the missing minute entered into evidence. Four quarters means four separate counts.'],['Universidad México','Six-minute quarters outside the chamber. Several productive decades inside it. UMX will adjust.'],['BYU','Shorter games mean fewer chances to recover from veteran mistakes. Chris plans to be the fastest coach to adapt.'],['Florida State','Glenn has already been hired to reset every stadium clock in Tallahassee. The NCAA is paying overtime.'],['Washington','Dusty says an accelerated clock is just a normal clock that finally received the correct wiring diagram.']]
  ,'byu-washington-week1':[['BYU','Down at halftime, up 36 at the finish. Stop calling him Dusty’s kid and start calling him the coach who scored 39 unanswered.'],['Washington','The first half looked classified. The second half looked like Chris found the password. Dusty has repairs to make.'],['South Carolina','Five touchdowns, zero interceptions, zero turnovers. Sam has entered Bachmeier into evidence as a Week 1 threat.'],['Florida State','Glenn says a 39–0 second half is either elite adjustment or a very productive night shift.'],['Universidad México','UMX welcomes Washington to the 0–1 recovery meeting. The first agenda item is surviving a second-half avalanche.']]
  ,'week1-national-reset':[['BYU','Top 10 after one game and the youngest coach owns the biggest user-team win. That is the proof Chris wanted.'],['Florida State','FSU beat a ranked team and still sits outside the poll. Glenn just accepted an extra shift printing bulletin-board material.'],['South Carolina','The reigning champion is 1–0 and unranked. Sam has opened an investigation into every voter.'],['Washington','Falling out hurts. Giving Chris family bragging rights hurts worse. Dusty has two weeks and one toolbox.'],['Universidad México','The Panteras are not ranked yet, but the national leaderboards confirm Week 1 gave everybody something to chase.']]
};
const voicesByTeam=Object.fromEntries(fanVoices.map(voice=>[voice.team,voice]));
const socialReactions=[...stories].reverse().flatMap((story,storyIndex)=>{let plan=conversationPlans[story.id];if(!plan){const count=2+(story.title.length%4);plan=fanVoices.slice(0,count).map((fan,index)=>[fan.team,fan.quips[(storyIndex+index)%fan.quips.length](storyAngles[story.id]||story.dek)])}return plan.map(([team,text],commentIndex)=>{const fan=voicesByTeam[team];const handle=fan.handles[(storyIndex+commentIndex)%fan.handles.length];return {...fan,handle,storyId:story.id,storyTitle:story.title,text}})});
