const oldMobile=document.querySelector('.mobile-social-ticker');if(oldMobile)oldMobile.remove();const mobileFeed=document.createElement('div');mobileFeed.className='mobile-social-ticker';mobileFeed.style.setProperty('--ticker-duration',`${Math.max(150,feedPosts.length*8)}s`);mobileFeed.innerHTML=`<b>JNN SOCIAL</b><div><span>${feedPosts.map(post=>`<i>${post.handle}</i> ${post.text}`).join(' &nbsp; ◆ &nbsp; ')}</span></div>`;document.body.append(mobileFeed);
